import { z } from 'zod';

// ============ Migration Schemas ============

export const MigrationStartSchema = z.object({
  sourceServerId: z.string(),
  targetServerId: z.string().optional(),
  mode: z.enum(['same_server', 'cross_server_staging', 'cross_server_bluegreen']),
});

export const MigrationGetSessionSchema = z.object({
  migrationId: z.string(),
});

export const MigrationGetItemsSchema = z.object({
  migrationId: z.string(),
});

export const MigrationSelectItemsSchema = z.object({
  migrationId: z.string(),
  selection: z.record(z.string(), z.boolean()),
});

export const MigrationExecuteSchema = z.object({
  migrationId: z.string(),
  selection: z.record(z.string(), z.boolean()),
});

export const MigrationVerifySchema = z.object({
  migrationId: z.string(),
});

export const MigrationRollbackSchema = z.object({
  migrationId: z.string(),
});

export const MigrationGetDecommissionPlanSchema = z.object({
  migrationId: z.string(),
});

export const MigrationExecuteDecommissionStepSchema = z.object({
  migrationId: z.string(),
  stepId: z.string(),
});

export const MigrationGetCutoverPlanSchema = z.object({
  migrationId: z.string(),
});

export const MigrationExecuteCutoverSchema = z.object({
  migrationId: z.string(),
});

export const MigrationCancelSchema = z.object({
  migrationId: z.string(),
});

export const MigrationGetHistorySchema = z.object({
  serverId: z.string(),
});

export const MigrationRetryItemSchema = z.object({
  migrationId: z.string(),
  itemId: z.string(),
});
